// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
import "./AuditLog.sol";

contract RoleManager {
    enum Role { NONE, ADMIN, TEACHER, STUDENT }
    mapping(address => Role) private userRoles;

    AuditLog public auditLog;

    constructor(address _auditLogAddress) {
        userRoles[msg.sender] = Role.ADMIN;
        auditLog = AuditLog(_auditLogAddress);
        auditLog.logEvent("RoleGranted", msg.sender, "System Admin Created");
    }

    modifier onlyAdmin() {
        require(userRoles[msg.sender] == Role.ADMIN, "Caller is not an admin");
        _;
    }

    function grantTeacher(address _user) external onlyAdmin {
        userRoles[_user] = Role.TEACHER;
        auditLog.logEvent("RoleGranted", _user, "Admin granted TEACHER role");
    }

    function grantStudent(address _user) external onlyAdmin {
        userRoles[_user] = Role.STUDENT;
        auditLog.logEvent("RoleGranted", _user, "Admin granted STUDENT role");
    }

    function revokeRole(address _user) external onlyAdmin {
        require(_user != msg.sender, "Cannot revoke own admin role");
        userRoles[_user] = Role.NONE;
        auditLog.logEvent("RoleRevoked", _user, "Admin revoked access");
    }

    function getRole(address _user) external view returns (string memory) {
        if (userRoles[_user] == Role.ADMIN) return "ADMIN";
        if (userRoles[_user] == Role.TEACHER) return "TEACHER";
        if (userRoles[_user] == Role.STUDENT) return "STUDENT";
        return "NONE";
    }
}
